import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import Navbar from "./components/Navbar";
import DesignerList from "./components/DesignerList";
import ComplaintList from "./components/ComplaintList";
import "./style.css";

// Home component
function Home() {
  return (
    <div className="home-container">
      {/* Dashboard Banner */}
      <div className="dashboard-banner">
        <img src="/images/dashboard-banner.jpg" alt="Dashboard Banner" />
        <div className="banner-text">
          <h2>Grow Your Brand with Impactful Advertising</h2>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="dashboard-cards">
        <div className="card card-blue">
          <FaUsers size={30} />
          <h3>Total Designers</h3>
          <p>25</p>
        </div>
        <div className="card card-green">
          <FaFileAlt size={30} />
          <h3>Total Complaints</h3>
          <p>40</p>
        </div>
        <div className="card card-yellow">
          <FaCalendarDay size={30} />
          <h3>Today's Complaints</h3>
          <p>5</p>
        </div>
      </div>
    </div>
  );
}

function App() {
  return (
    <Router>
      <div className="app-container">
        <Navbar />
        <div className="content">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/designers" element={<DesignerList />} />
            <Route path="/complaints" element={<ComplaintList />} />
          </Routes>
        </div>
      </div>
    </Router>
  );
}

export default App;
